module HistoryRecordEntry =
  struct
    type nonrec t =
      {
      eventInformation: EventInformation.t option
        [@ocaml.doc "Information about the event."];
      eventType: FleetEventType.t option [@ocaml.doc "The event type."];
      timestamp: DateTime.t option
        [@ocaml.doc
          "The date and time of the event, in UTC format (for example, YYYY-MM-DDTHH:MM:SSZ)."]}
    let make ?eventInformation =
      fun ?eventType ->
        fun ?timestamp ->
          fun () -> { eventInformation; eventType; timestamp }
    let to_value x =
      structure_to_value
        [("eventInformation",
           (Option.map x.eventInformation ~f:EventInformation.to_value));
        ("eventType", (Option.map x.eventType ~f:FleetEventType.to_value));
        ("timestamp", (Option.map x.timestamp ~f:DateTime.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let timestamp =
        (Option.map ~f:DateTime.of_xml) (Xml.child xml_arg0 "timestamp") in
      let eventType =
        (Option.map ~f:FleetEventType.of_xml)
          (Xml.child xml_arg0 "eventType") in
      let eventInformation =
        (Option.map ~f:EventInformation.of_xml)
          (Xml.child xml_arg0 "eventInformation") in
      make ?timestamp ?eventType ?eventInformation ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let timestamp = field_map json__ "Timestamp" DateTime.of_json in
      let eventType = field_map json__ "EventType" FleetEventType.of_json in
      let eventInformation =
        field_map json__ "EventInformation" EventInformation.of_json in
      make ?timestamp ?eventType ?eventInformation ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Describes an event in the history of an EC2 Fleet."]